INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-1528', '108', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.6', '[ELO3] Develop hand-created or digital presentation styles that enhance writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1529', '109', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.7', '[ELO3] Share writing and other representations with others and seek response.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1530', '110', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.8', '[ELO3] With assistance, experiment with technology in writing and other forms of representing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1531', '111', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.1', '[ELO1] Listen and respond for pleasure to fiction, nonfiction, and poetry.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1532', '112', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.2', '[ELO1] Use Listening Comprehension Strategies to make and simplify meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1533', '113', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.3', '[ELO1] Retell a story and support opinions with examples from the text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1534', '114', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.4', '[ELO1] Begin to use self-monitoring strategies to detect when miscues affect meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1535', '115', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.5', '[ELO1] Listen to follow and give directions with increasing complexity.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1536', '116', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.6', '[ELO1] Listen and speak for enjoyment of playful language through songs, verses, and rhymes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1537', '117', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.7', '[ELO1] Develop awareness of the purpose of language change in different situations.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1538', '118', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.8', '[ELO1] Continue to use Home Language and Standard English vocabulary during speaking activities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1539', '119', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.9', '[ELO1] Use vocabulary appropriate to topic and audience.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1540', '120', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.10', '[ELO1] Demonstrate understanding and use of conversation courtesies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1541', '121', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.11', '[ELO1] Listen attentively and build on others'' ideas with increasing confidence.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1542', '122', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.12', '[ELO1] Begin to listen to understand without expressing judgment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1543', '123', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.13', '[ELO1] Continue to develop an appreciation and celebration of cultural diversity.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1544', '124', 'language-arts', '2', 'Listening and Speaking', 'LA_GR2_ST1_ELO1_1.14', '[ELO1] Engage in active phonological awareness activities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1545', '125', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.1', '[ELO1] Continue to make engaging and just right book choices for Independent Reading.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1546', '126', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.2', '[ELO1] Reflect on various sources of background knowledge to predict and make connections.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1547', '127', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.3', '[ELO1] Increase time (build stamina) while engaged in Independent Reading.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1548', '128', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.4', '[ELO1] Regard reading/viewing as sources of interest, enjoyment, and information.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1549', '129', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.5', '[ELO1] Share ideas and opinions about favourite authors or favourite genres with peers.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1550', '130', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.6', '[ELO1] Make meaningful personal, text and community/world connections that enhance comprehension.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-1551', '131', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.7', '[ELO1] Demonstrate understanding and application of reading strategies while reading Early level texts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1552', '133', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.9', '[ELO1] Make connections between personal and social wellbeing and information texts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1553', '134', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.10', '[ELO1] Recognize different points of view of the author of print and/or digital text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1554', '135', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.11', '[ELO1] Continue to develop an understanding and respect for diversity in text and illustrations.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1555', '136', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.12', '[ELO1] Use illustrations and details in a text to describe and interpret characters, setting, and events.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1556', '137', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.13', '[ELO1] Reflect on the purpose of different types of texts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1557', '138', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.1', '[ELO2] Recognise the purpose and basic similarities and differences in paper based and digital genres of fiction, nonfiction, and poetry.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1558', '139', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.2', '[ELO2] Apply a variety of comprehension strategies to create meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1559', '140', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.3', '[ELO2] Use illustrations, graphics etc. in nonfiction text to ask questions, make inferences, and search for answers.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1560', '141', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.4', '[ELO2] Use various tools to retell a narrative, referring to characters, problem, and solution.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1561', '142', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.5', '[ELO2] Read simple mathematics or science problems to search for information, ask questions, and find solutions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1562', '143', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.6', '[ELO2] Demonstrate understanding through various responses to text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1563', '144', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.7', '[ELO2] Follow written instructions to create an object, find a location, etc.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1564', '145', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.8', '[ELO2] Begin to connect background knowledge re community and culture to support comprehension of culturally relevant text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1565', '146', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO2_3.9', '[ELO2] Respond critically to texts by asking and formulating responses to questions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1566', '147', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.1', '[ELO3] Continue to build familiarity with a variety of local and favourite international authors.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1567', '148', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.2', '[ELO3] Continue to develop understanding through reading and viewing how texts are organized.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1568', '149', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.3', '[ELO3] Engage in Shared Reading and Readers Theatre.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1569', '150', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.4', '[ELO3] Begin to notice author''s choices related to descriptive language, dialogue, illustrations.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1570', '151', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.5', '[ELO3] Continue to develop strategies to begin Independent Reading with purpose and interest.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1571', '152', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.6', '[ELO3] Discuss author''s use of vocabulary and sentences that add to the mood and personal engagement.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1572', '153', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.7', '[ELO3] Continue to develop word relationships vocabulary.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1573', '154', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO3_4.8', '[ELO3] Continue to develop an understanding of how written word order impacts meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1574', '155', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.1', '[ELO1] Continue to develop strategies for the prewriting stage of the writing process.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1575', '156', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.2', '[ELO1] Use graphic organizers to brainstorm and plan.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1576', '157', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.3', '[ELO1] Participate in shared writing opportunities that reflect the genre studied.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1577', '158', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.4', '[ELO1] Continue to develop understanding and independent use of writing traits.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1578', '159', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.5', '[ELO1] Draft in different forms with more specific understanding of their purpose and organization.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1579', '160', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.6', '[ELO1] Experiment with transition words to develop a logical progression of ideas.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1580', '161', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.7', '[ELO1] Use anchor texts to guide sentence and paragraph development.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1581', '162', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO1_5.8', '[ELO1] Continue to develop understanding of how to organise ideas in a paragraph.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1582', '163', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.1', '[ELO2] Continue to develop self assessment revision strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1583', '164', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.2', '[ELO2] Use feedback given by peers and teachers to strengthen the organization of the draft.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1584', '165', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.3', '[ELO2] Continue to appreciate and develop the purpose and place of Home Language and Standard English vocabulary.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1585', '166', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.4', '[ELO2] Continue to develop self monitoring of errors in word use.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1586', '167', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.5', '[ELO2] Choose and use descriptive vocabulary during revision.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1587', '168', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.6', '[ELO2] Use a dictionary or prompts to clarify the meaning of keywords.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1588', '169', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.7', '[ELO2] Continue to engage in peer revision opportunities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1589', '170', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO2_6.8', '[ELO2] Revise with a focus on the use of simple verb tenses, comparative adjectives and adverbs, and subject and verb agreement.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1590', '171', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.1', '[ELO3] Use reference material to check and/or confirm commonly used words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1591', '172', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.2', '[ELO3] Generate spelling of unfamiliar words based on sounds, patterns, and spelling rules.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1592', '173', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.3', '[ELO3] Demonstrate increasing knowledge of more complex spelling patterns.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1593', '174', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.4', '[ELO3] Apply a wider range of spelling strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1594', '175', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.5', '[ELO3] Continue to develop the use of digital features such as spell check.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1595', '176', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.6', '[ELO3] Continue to refine the use of grade-level punctuation conventions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1596', '177', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.7', '[ELO3] Make final corrections of revised draft.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1597', '178', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.8', '[ELO3] Self-select final pieces of writing to publish.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1598', '179', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.9', '[ELO3] Use conventional spacing between words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1599', '180', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.10', '[ELO3] Continue to refine letter formation to increase readability.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1600', '181', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.11', '[ELO3] Develop hand-created or digital presentation styles that enhance writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-1601', '182', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.12', '[ELO3] Share writing and other representations with others and seek response.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1602', '183', 'language-arts', '2', 'Writing and Representing', 'LA_GR2_ST3_ELO3_7.13', '[ELO3] With assistance, experiment with technology in writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1603', '184', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.1', '[ELO1] Engage with and share various genres of music, oral poetry, artwork, and oral stories that have been chosen for pleasure.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1604', '185', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.2', '[ELO1] Experience and enjoy playful use of language, to communicate e.g., telling jokes, asking riddles, singing songs, composing rhymes and verses.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1605', '186', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.3', '[ELO1] Respond to oral/aural language through improvisational drama and/or artwork.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1606', '187', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.4', '[ELO1] Listen attentively and critically to fiction and nonfiction text and music to demonstrate understanding of the mood, main idea, and some supporting details.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1607', '188', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.5', '[ELO1] Continue to develop strategies to describe, share, and discuss thoughts, feelings, and experiences with peers.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1608', '189', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.6', '[ELO1] Ask and respond to questions to clarify information and to explore possibilities or solutions to problems.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1609', '190', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.7', '[ELO1] Listen critically for subtle messages in conversation, music, and environmental sounds.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1610', '191', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.8', '[ELO1] Create and use oral instructions describing how to make or do something.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1611', '192', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.9', '[ELO1] Discuss solutions to local, regional and world events by extending use of questioning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1612', '193', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.10', '[ELO1] Demonstrate understanding and use of conversation courtesies during peer group work, class discussions and play.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1613', '194', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.11', '[ELO1] Use vocabulary that shows respect for all people.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1614', '195', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.12', '[ELO1] Listen attentively and build on others'' ideas with increasing confidence.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1615', '196', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.13', '[ELO1] Continue to develop understanding of point of view without expressing judgment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1616', '197', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.14', '[ELO1] Explore ideas and feelings by asking respectful questions and listening with minimal interruption.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1617', '198', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.15', '[ELO1] Develop an understanding and appreciation of various cultural traditions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1618', '199', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.16', '[ELO1] Demonstrate awareness that language can influence and persuade.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1619', '200', 'language-arts', '3', 'Listening and Speaking', 'LA_GR3_ST1_ELO1_1.17', '[ELO1] Continue to explore the connections between oral and written language.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1620', '201', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.1', '[ELO1] Continue to expand their book choices based on genre, difficulty, and interest.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1621', '202', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.2', '[ELO1] Reflect on various sources of background knowledge to predict and make connections.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1622', '203', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.3', '[ELO1] Increase time (build stamina) while engaged in Independent Reading.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1623', '204', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.4', '[ELO1] Recognize how understanding may change as more information is gathered.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1624', '205', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.5', '[ELO1] Share ideas and opinions about favourite authors or favourite genres.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1625', '206', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.6', '[ELO1] Make meaningful personal, text and community/world connections.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1626', '207', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.7', '[ELO1] Extend understanding of how background knowledge impacts comprehension.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1627', '208', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.8', '[ELO1] Use illustrations and details in a text to describe and interpret characters, setting, and events.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1628', '209', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.9', '[ELO1] Expand understanding of diverse points of view.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1629', '210', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO1_2.10', '[ELO1] Use text features to support independent and small group research.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1630', '211', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.1', '[ELO2] Explore and discuss the purpose of fiction, nonfiction, poetry, and drama.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1631', '212', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.2', '[ELO2] Apply a variety of comprehension strategies to create meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1632', '213', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.3', '[ELO2] Use various formats to retell a narrative and identify elements of story.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1633', '214', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.4', '[ELO2] Distinguish between main idea and supporting information.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1634', '215', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.5', '[ELO2] Respond with understanding to visual/written instructions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1635', '216', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.6', '[ELO2] Continue to expand vocabulary through a variety of means.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1636', '217', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.7', '[ELO2] Continue to develop decoding strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1637', '218', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.8', '[ELO2] Demonstrate understanding of how word order impacts meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1638', '219', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.9', '[ELO2] Continue to apply understanding of how reading fluency impacts comprehension.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1639', '220', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.10', '[ELO2] Participate in shared reading opportunities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1640', '221', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO2_3.11', '[ELO2] Apply knowledge of roots, affixes, and syllabication to decode unknown words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1641', '222', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO3_4.1', '[ELO3] Continue to recognize and identify the author''s purpose.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1642', '223', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO3_4.2', '[ELO3] Continue to develop an understanding of author''s style and purpose.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1643', '224', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO3_4.3', '[ELO3] Explore use of literary devices (similes, metaphors, onomatopoeia, personification).', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1644', '225', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO3_4.4', '[ELO3] Continue to discuss author''s vocabulary that evokes emotion.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1645', '226', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO3_4.5', '[ELO3] Continue to develop understanding of text structures and genres.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1646', '227', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO3_4.6', '[ELO3] Refine meaningful and critical use of text features to locate and use information.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1647', '228', 'language-arts', '3', 'Reading and Viewing', 'LA_GR3_ST2_ELO3_4.7', '[ELO3] Evaluate the purpose of graphic information.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1648', '229', 'language-arts', '3', 'Writing and Representing', 'LA_GR3_ST3_ELO1_5.1', '[ELO1] Apply knowledge of prewriting strategies with increasing independence.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1649', '230', 'language-arts', '3', 'Writing and Representing', 'LA_GR3_ST3_ELO1_5.2', '[ELO1] Continue to use a variety of information gathering strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1650', '231', 'language-arts', '3', 'Writing and Representing', 'LA_GR3_ST3_ELO1_5.3', '[ELO1] Begin to use note-taking strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-1651', '232', 'language-arts', '3', 'Writing and Representing', 'LA_GR3_ST3_ELO1_5.4', '[ELO1] Expand use of print, media, and technology sources.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
