  ('legacy-sco-1714', '295', 'language-arts', '4', 'Reading and Viewing', 'LA_GR4_ST2_ELO1_2.11', '[ELO1] Foster critical thinking skills and appreciation for the relationship between words and images.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1715', '296', 'language-arts', '4', 'Reading and Viewing', 'LA_GR4_ST2_ELO1_2.12', '[ELO1] Apply higher-order thinking skills.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1716', '297', 'language-arts', '4', 'Reading and Viewing', 'LA_GR4_ST2_ELO1_2.13', '[ELO1] Deepen understanding of the purpose and influences of different types of popular texts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
