  ('legacy-sco-1722', '303', 'language-arts', '4', 'Reading and Viewing', 'LA_GR4_ST2_ELO2_3.6', '[ELO2] Expand vocabulary through reading a range of authors, topics, and genres.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1723', '304', 'language-arts', '4', 'Reading and Viewing', 'LA_GR4_ST2_ELO2_3.7', '[ELO2] Utilize print, digital and personal dictionaries.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
