  ('legacy-sco-1728', '309', 'language-arts', '4', 'Reading and Viewing', 'LA_GR4_ST2_ELO2_3.12', '[ELO2] Further develop awareness of how word choice and phrasing may describe persons and events.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
