  ('legacy-sco-1730', '311', 'language-arts', '4', 'Reading and Viewing', 'LA_GR4_ST2_ELO2_3.14', '[ELO2] Deepen application of knowledge of roots, affixes, and syllabication.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
