  ('legacy-sco-1839', '420', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.4', '[ELO2] Continue to develop self monitoring of errors.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1840', '421', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.5', '[ELO2] Choose and use vocabulary with purpose.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1841', '422', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.6', '[ELO2] Use a dictionary or thesaurus.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1842', '423', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.7', '[ELO2] Continue to recognize and use words with multiple meanings.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1843', '424', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.8', '[ELO2] Continue to engage in peer revision opportunities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1844', '425', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.9', '[ELO2] Revise with a focus on grammar and sentence fluency.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1845', '426', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.10', '[ELO2] Continue to use digital grammar checker.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1846', '427', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO2_6.11', '[ELO2] Make use of figurative language to enhance writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1847', '428', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.1', '[ELO3] Continue to apply learning in spelling.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1848', '429', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.2', '[ELO3] Transfer understanding of spelling conventions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1849', '430', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.3', '[ELO3] Further develop self-monitoring strategies for spelling.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1850', '431', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.4', '[ELO3] Develop proficiency in punctuation conventions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-1851', '432', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.5', '[ELO3] Make decisions about strategic use of punctuation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1852', '433', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.6', '[ELO3] Connect punctuation choice to style and format.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1853', '434', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.7', '[ELO3] Employ a range of presentation formats.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1854', '435', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.8', '[ELO3] Integrate visual elements into written work.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1855', '436', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.9', '[ELO3] Publish written work for varying audiences.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1856', '437', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.10', '[ELO3] Engage in collaborative projects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1857', '438', 'language-arts', '5', 'Writing and Representing', 'LA_GR5_ST3_ELO3_7.11', '[ELO3] Add titles, cover images, tables of content, etc.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1858', '439', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.1', '[ELO1] Participate in opportunities to develop oral language through class discussions, debates, storytelling, oral poetry, and singing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1859', '440', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.2', '[ELO1] Continue to explore a variety of genres and styles in spoken language on topics of interest and personal growth.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1860', '441', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.3', '[ELO1] Express preferences in written, visual, and oral communication genres and styles and explain the reasons behind their choices.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1861', '442', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.4', '[ELO1] Use technology to enhance listening and speaking skills, such as recording and listening to their own speech, creating podcasts, live streams, videos.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1862', '443', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.5', '[ELO1] Speak and listen critically to explore, extend, clarify, and reflect on their thoughts, ideas, feelings, and experiences.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1863', '444', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.6', '[ELO1] Listen to oral presentations to identify useful details for application.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1864', '445', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.7', '[ELO1] Listen to speeches, songs, poems etc. to determine literal and inferential meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1865', '446', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.8', '[ELO1] Listen to traditional stories and songs to learn about culture, history, and social justice issues.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1866', '447', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.9', '[ELO1] Listen to audio material to expand cultural perspectives/identify differences among cultures and subcultures.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1867', '448', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.10', '[ELO1] Formulate and ask questions for clarification.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1868', '449', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.11', '[ELO1] Apply knowledge of Home Language(s) and Standard English to understand how language functions in different contexts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1869', '450', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.12', '[ELO1] Use vocabulary appropriate to topic and audience.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1870', '451', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.13', '[ELO1] Demonstrate command of the conventions of Standard English grammar and usage.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1871', '452', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.14', '[ELO1] Use precise language and domain-specific vocabulary.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1872', '453', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.15', '[ELO1] Integrate and evaluate information presented in diverse media and formats.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1873', '454', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.16', '[ELO1] Contribute thoughts, ideas, and questions to class or peer group discussions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1874', '455', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.17', '[ELO1] Listen critically to others'' ideas or opinions and points of view.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1875', '456', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.18', '[ELO1] Present/discuss information that is accurate, states a topic, follows an organizational structure.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1876', '457', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.19', '[ELO1] Present information, findings, and supporting evidence clearly, concisely, and logically.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1877', '458', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.20', '[ELO1] Demonstrate attentive listening in non-verbal ways.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1878', '459', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.21', '[ELO1] Synthesize viewpoints of others and discuss options to resolve differences.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1879', '460', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.22', '[ELO1] Use appropriate strategies for making connections with audience.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1880', '461', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.23', '[ELO1] Identify strategies they found most useful for listening and speaking.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1881', '462', 'language-arts', '6', 'Listening and Speaking', 'LA_GR6_ST1_ELO1_1.24', '[ELO1] Identify persuasive and propaganda techniques used in oral communications.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1882', '463', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.1', '[ELO1] Select from a range of genres for Independent Reading based on interests, subject areas, and appropriate level.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1883', '464', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.2', '[ELO1] Connect with background knowledge to comprehend text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1884', '465', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.3', '[ELO1] Read widely and experience a variety of genres from the Caribbean and international cultures.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1885', '466', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.4', '[ELO1] Reflect on and identify strengths and areas for improvement as readers.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1886', '467', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.5', '[ELO1] Use text features to locate information and verify understanding.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1887', '468', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.6', '[ELO1] Demonstrate critical questioning strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1888', '469', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.7', '[ELO1] Apply problem-solving strategies to follow multi-step instructions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1889', '470', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.8', '[ELO1] Use Independent Reading Time to develop fluency.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1890', '471', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.9', '[ELO1] Use all sources of information to self-monitor and self-correct.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1891', '472', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.10', '[ELO1] Understand how illustrations enhance meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1892', '473', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.11', '[ELO1] Apply higher-order thinking skills.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1893', '474', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO1_2.12', '[ELO1] Deepen understanding of purpose and influences of different text types.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1894', '475', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO2_3.1', '[ELO2] Use prior knowledge and critical thinking skills.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1895', '476', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO2_3.2', '[ELO2] Demonstrate ability to use comprehension strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1896', '477', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO2_3.3', '[ELO2] Utilize contextual clues to derive meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1897', '478', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO2_3.4', '[ELO2] Analyse and synthesise connections.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1898', '479', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO2_3.5', '[ELO2] Use dictionaries to aid comprehension.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1899', '480', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO2_3.6', '[ELO2] Expand vocabulary through reading.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1900', '481', 'language-arts', '6', 'Reading and Viewing', 'LA_GR6_ST2_ELO2_3.7', '[ELO2] Gain vocabulary through visual and written media.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
