  ('legacy-sco-2631', '1', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_K01', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Knowledge] Demonstrate an understanding of "me" as a unique child.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2632', '2', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_K02', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Knowledge] Name family members.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2633', '3', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_K03', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Knowledge] Understand that we inherit characteristics from our families.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2634', '4', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_K04', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Knowledge] Recognize that their own physical characteristics, preferences, and mannerisms may be inherited from their families.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2635', '5', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_K05', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Knowledge] Understand that respect for self includes proper cleanliness, language and behaviour.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2636', '6', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_S01', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Skills] Distinguish personal characteristics that make each child unique (physical traits, mannerisms).', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2637', '7', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_S02', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Skills] Represent family members using pictures/images.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2638', '8', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_S03', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Skills] Compare their physical features with those of their family members; categorize similarities and differences of self and other family members.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2639', '9', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_S04', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Skills] Categorize similarities and differences of self and others in families.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2640', '10', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_V01', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Values] Appreciate that everyone has unique and special characteristics.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2641', '11', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_V02', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Values] Express appreciation of the child''s own personal attributes, one''s name.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2642', '12', 'social-studies', 'K', 'Historical and Cultural Thinking', 'SS_GRK_ST1_H1.1_V03', '[ELO H1.1 - Recognizing Uniqueness of Self and Family - Values] Appreciate the uniqueness of families; respect that the composition of families takes many forms.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
