INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-2951', '321', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.2_V01', '[ELO H1.2 - Using Communication Media Effectively - Values] Appreciate the need to critically analyse information in the media.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2952', '322', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.3_K01', '[ELO H1.3 - Early Settlement and Colonisation - Knowledge] Identify the settlement patterns of Europeans in the Lesser and Greater Antilles from the 1400s-1800s.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2953', '323', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.3_S01', '[ELO H1.3 - Early Settlement and Colonisation - Skills] Examine how the Caribbean was negatively and positively affected by European colonisation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2954', '324', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.3_V01', '[ELO H1.3 - Early Settlement and Colonisation - Values] Recognize that colonisation had lasting effects on the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2955', '325', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.4_K01', '[ELO H1.4 - The African Slave Trade - Knowledge] Explain why colonial powers brought enslaved Africans to the Caribbean in the 1600s-1800s.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2956', '326', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.4_S01', '[ELO H1.4 - The African Slave Trade - Skills] Map the route of the triangular slave trade.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2957', '327', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.4_V01', '[ELO H1.4 - The African Slave Trade - Values] Develop an awareness of how the introduction of Africans as slaves has impacted our (economic, cultural, and political) history.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2958', '328', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.5_K01', '[ELO H1.5 - Active Resistance to Slavery - Knowledge] Identify the ways that enslaved Africans in the Caribbean resisted bondage.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2959', '329', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.5_S01', '[ELO H1.5 - Active Resistance to Slavery - Skills] Categorise the forms of resistance into everyday actions and armed rebellion.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2960', '330', 'social-studies', '5', 'Historical and Cultural Thinking', 'SS_GR5_ST1_H1.5_V01', '[ELO H1.5 - Active Resistance to Slavery - Values] Recognise that resistance to enslavement took great courage and required cooperation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2961', '331', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.1_K01', '[ELO S1.1 - Geographic Classifications of Caribbean - Knowledge] Describe various classifications of the Caribbean region such as Bahamas, Greater and Lesser Antilles, Windward and Leeward Islands, and Caribbean coastal areas (mainland territories).', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2962', '332', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.1_S01', '[ELO S1.1 - Geographic Classifications of Caribbean - Skills] Plot on a map linguistic, political, and economic information for each classification of the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2963', '333', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.1_V01', '[ELO S1.1 - Geographic Classifications of Caribbean - Values] Appreciate that the location of the different islands/territories brought about differing positive and negative consequences for their people.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2964', '334', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.2_K01', '[ELO S1.2 - Physical Formation of Caribbean Islands - Knowledge] Describe the geographic differences between coral and volcanic island formations.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2965', '335', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.2_S01', '[ELO S1.2 - Physical Formation of Caribbean Islands - Skills] Explain the impact of different island types on the economy and people''s way of life.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2966', '336', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.2_V01', '[ELO S1.2 - Physical Formation of Caribbean Islands - Values] Appreciate that both volcanic and coral islands hold environmental and economic benefits and pose challenges.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2967', '337', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.3_K01', '[ELO S1.3 - Major Landmarks in the Region - Knowledge] Identify popular/major landmarks (natural and built) in the region.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2968', '338', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.3_S01', '[ELO S1.3 - Major Landmarks in the Region - Skills] Map the location of important landmarks in the region.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2969', '339', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.3_V01', '[ELO S1.3 - Major Landmarks in the Region - Values] Appreciate the value (economic, cultural, historical) of familiar landmarks to the development of the region.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2970', '340', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.4_K01', '[ELO S1.4 - Our Climate - Knowledge] Describe climatic differences across the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2971', '341', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.4_S01', '[ELO S1.4 - Our Climate - Skills] Plot the coordinates of various islands and display differences in temperature and rainfall.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2972', '342', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.4_V01', '[ELO S1.4 - Our Climate - Values] Appreciate the importance of climate and climate changes for shaping the economy, society, and policy decisions of various areas of the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2973', '343', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.5_K01', '[ELO S1.5 - Climate Change and Its Effects - Knowledge] Identify how climatic similarities and severe weather events associated with climate change have fostered cooperation (e.g. Leeward islands and freshwater).', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2974', '344', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.5_S01', '[ELO S1.5 - Climate Change and Its Effects - Skills] Plot major climatic disasters in the region over the past 50 years and note changes related to climate change and assess their negative effects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2975', '345', 'social-studies', '5', 'Spatial Thinking', 'SS_GR5_ST3_S1.5_V01', '[ELO S1.5 - Climate Change and Its Effects - Values] Assess the ways that Caribbean countries have assisted one another in recent climate disasters especially as it has related to climate change.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-2976', '346', 'social-studies', '5', 'Civic Participation', 'SS_GR5_ST2_C1.1_K01', '[ELO C1.1 - Caribbean Government Systems - Knowledge] Identify the various types of government systems in the region.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
