  ('legacy-sco-3003', '373', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.4_K01', '[ELO E1.4 - Regional Trade and Communication Networks - Knowledge] Explore the development of regional transportation and communication linkages in the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3004', '374', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.4_S01', '[ELO E1.4 - Regional Trade and Communication Networks - Skills] Trace the evolution of transportation and communication networks in the Caribbean region.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3005', '375', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.4_V01', '[ELO E1.4 - Regional Trade and Communication Networks - Values] Appreciate that the development of transportation and communication networks has brought many benefits to the region while many challenges persist.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3006', '376', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.5_K01', '[ELO E1.5 - Transportation and Trade - Knowledge] Identify how transportation and communication support trade between Caribbean countries.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3007', '377', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.5_S01', '[ELO E1.5 - Transportation and Trade - Skills] Analyse how improvements in transportation and communication impact trade in the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3008', '378', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.5_V01', '[ELO E1.5 - Transportation and Trade - Values] Appreciate the role of transportation and communication in promoting economic stability and growth in the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3009', '379', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.6_K01', '[ELO E1.6 - Benefits of Regional Trade - Knowledge] Explain the economic benefits our country derives from relationships with our Caribbean neighbours.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3010', '380', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.6_S01', '[ELO E1.6 - Benefits of Regional Trade - Skills] Chart and compare positive and negative impacts of trade with other countries.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3011', '381', 'social-studies', '5', 'Economic Decision Making', 'SS_GR5_ST4_E1.6_V01', '[ELO E1.6 - Benefits of Regional Trade - Values] Appreciate that trade relationships can affect both the economy and the everyday lives of people in your country and neighbouring countries.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3012', '382', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.1_K01', '[ELO H1.1 - Slavery and Emancipation - Knowledge] Identify the groups that worked to end slavery.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3013', '383', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.1_S01', '[ELO H1.1 - Slavery and Emancipation - Skills] Build a timeline of major milestones in the struggle for emancipation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3014', '384', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.1_V01', '[ELO H1.1 - Slavery and Emancipation - Values] Value the contribution of the enslaved people in resisting slavery and achieving emancipation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3015', '385', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.2_K01', '[ELO H1.2 - East Indian Caribbean Cultures - Knowledge] Explain why East Indians were brought to the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3016', '386', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.2_S01', '[ELO H1.2 - East Indian Caribbean Cultures - Skills] Chart the route taken by East Indian Indentured Servants from their homeland to the Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3017', '387', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.2_V01', '[ELO H1.2 - East Indian Caribbean Cultures - Values] Appreciate the influences that East Indians have on Caribbean culture.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3018', '388', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.3_K01', '[ELO H1.3 - Arts and Sports in the Caribbean - Knowledge] Describe common sport, culture and music activities that foster regional interactions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3019', '389', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.3_S01', '[ELO H1.3 - Arts and Sports in the Caribbean - Skills] Investigate local sport, culture or music figures that have influence beyond their home state.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3020', '390', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.3_V01', '[ELO H1.3 - Arts and Sports in the Caribbean - Values] Appreciate the value of arts and sports for shaping regional identity and pride.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3021', '391', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.4_K01', '[ELO H1.4 - Migration - Knowledge] Identify places where people from the Eastern Caribbean have migrated to.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3022', '392', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.4_S01', '[ELO H1.4 - Migration - Skills] Locate where people of the Caribbean migrate.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3023', '393', 'social-studies', '6', 'Historical and Cultural Thinking', 'SS_GR6_ST1_H1.4_V01', '[ELO H1.4 - Migration - Values] Appreciate reasons why people migrate from their country and its impact on them and their home country.', NULL, NULL, NULL, NULL, NULL, NULL, 'Historical and Cultural Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3024', '394', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.1_K01', '[ELO S1.1 - Continents and Water Bodies - Knowledge] Name the continents and major water bodies of the world.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3025', '395', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.1_S01', '[ELO S1.1 - Continents and Water Bodies - Skills] Locate the continents and major water bodies of the world on a map or globe.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3026', '396', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.1_V01', '[ELO S1.1 - Continents and Water Bodies - Values] Recognize that continents are made up of different countries.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3027', '397', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.2_K01', '[ELO S1.2 - Climatic Regions - Knowledge] Identify the climatic regions of the world (tropical/torrid, temperate and polar/frigid) and describe their physical characteristics (e.g. deserts, tundra, forests, mountains, plains).', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3028', '398', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.2_S01', '[ELO S1.2 - Climatic Regions - Skills] Illustrate how other regions are alike or different from our region.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3029', '399', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.2_V01', '[ELO S1.2 - Climatic Regions - Values] Appreciate that all regions of the world have unique natural features.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3030', '400', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.3_K01', '[ELO S1.3 - Adaptation and Lifestyle in Diverse Regions - Knowledge] Describe how people in the various regions live (housing, clothing, agriculture, social life, transportation).', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3031', '401', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.3_S01', '[ELO S1.3 - Adaptation and Lifestyle in Diverse Regions - Skills] Analyze the advantages and disadvantages of living in the various regions of the world.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3032', '402', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.3_V01', '[ELO S1.3 - Adaptation and Lifestyle in Diverse Regions - Values] Appreciate that the major regions each have unique features that help determine how people live there.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3033', '403', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.4_K01', '[ELO S1.4 - Extreme Climatic Conditions - Knowledge] Describe the extreme climatic conditions of these regions and explain how they are managed (e.g. snow, windstorms, tsunamis).', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3034', '404', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.4_S01', '[ELO S1.4 - Extreme Climatic Conditions - Skills] Analyse the impact of extreme climatic conditions on people and their environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3035', '405', 'social-studies', '6', 'Spatial Thinking', 'SS_GR6_ST3_S1.4_V01', '[ELO S1.4 - Extreme Climatic Conditions - Values] Appreciate that extreme climatic conditions have led to significant adaptations in the use of technology for securing food, shelter, clothing, and transportation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Spatial Thinking', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3036', '406', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.1_K01', '[ELO C1.1 - Our National Identities - Knowledge] Demonstrate understanding of factors which influence our national identity.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3037', '407', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.1_S01', '[ELO C1.1 - Our National Identities - Skills] Research an aspect of our national identity to show how it is influenced.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3038', '408', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.1_V01', '[ELO C1.1 - Our National Identities - Values] Appreciate the diverse ways that citizens demonstrate pride for their national identity.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3039', '409', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.2_K01', '[ELO C1.2 - International Organizations - Knowledge] Recognize that their country belongs to different international organisations.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3040', '410', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.2_S01', '[ELO C1.2 - International Organizations - Skills] Examine the different international organizations to which their country belongs.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3041', '411', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.2_V01', '[ELO C1.2 - International Organizations - Values] Appreciate that cooperation is necessary for a country''s development.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3042', '412', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.3_K01', '[ELO C1.3 - Social Issues - Knowledge] Identify the major social issues in the Eastern Caribbean and the nearby world.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3043', '413', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.3_S01', '[ELO C1.3 - Social Issues - Skills] Examine why these issues occur, how they can be solved, how they affect us in the Eastern Caribbean.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3044', '414', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.3_V01', '[ELO C1.3 - Social Issues - Values] Appreciate that people have differing views on how to address social issues.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3045', '415', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.4_K01', '[ELO C1.4 - International Cooperation - Knowledge] Discuss how different international organizations work to address social issues (WHO, FAO, IOM, UNICEF).', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3046', '416', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.4_S01', '[ELO C1.4 - International Cooperation - Skills] Categorize the advantages and disadvantages of being a member of an international organization.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3047', '417', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.4_V01', '[ELO C1.4 - International Cooperation - Values] Appreciate the ways in which citizens of the Eastern Caribbean cooperate to do things for the country.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3048', '418', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.5_K01', '[ELO C1.5 - Electoral Process and Democratic Rights - Knowledge] Examine the role of citizens in the electoral process.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3049', '419', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.5_S01', '[ELO C1.5 - Electoral Process and Democratic Rights - Skills] Discuss the importance of participating in the electoral process as part of peoples'' democratic rights.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3050', '420', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.5_V01', '[ELO C1.5 - Electoral Process and Democratic Rights - Values] Value the importance of respecting person''s democratic rights.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-3051', '421', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.6_K01', '[ELO C1.6 - Media and Society - Knowledge] Explain the role of the media in shaping our views of local and international events.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3052', '422', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.6_S01', '[ELO C1.6 - Media and Society - Skills] Compare and analyze media sources from various countries to determine differing points of view about important events and issues.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3053', '423', 'social-studies', '6', 'Civic Participation', 'SS_GR6_ST2_C1.6_V01', '[ELO C1.6 - Media and Society - Values] Appreciate that as global citizens we have a responsibility to verify the accuracy of the media we consume and to engage responsibly in its use.', NULL, NULL, NULL, NULL, NULL, NULL, 'Civic Participation', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3054', '424', 'social-studies', '6', 'Economic Decision Making', 'SS_GR6_ST4_E1.1_K01', '[ELO E1.1 - Consumer Rights and Responsibilities - Knowledge] Know that as consumers we have rights and responsibilities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3055', '425', 'social-studies', '6', 'Economic Decision Making', 'SS_GR6_ST4_E1.1_S01', '[ELO E1.1 - Consumer Rights and Responsibilities - Skills] Plan and develop budgets to guide our consumption.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
  ('legacy-sco-3056', '426', 'social-studies', '6', 'Economic Decision Making', 'SS_GR6_ST4_E1.1_V01', '[ELO E1.1 - Consumer Rights and Responsibilities - Values] Appreciate the value of making responsible decisions as consumers for shaping our economic and social well-being.', NULL, NULL, NULL, NULL, NULL, NULL, 'Economic Decision Making', '2026-01-04T14:07:47.797776+00:00', '2026-01-04T14:07:47.797776+00:00'),
